#include <iostream>
#include <iomanip>
#include <vector>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<vector<int>> a(N, vector<int>(N));
    int num = 1;
    for (int i = 0; i < N; ++i) {
        if (i % 2 == 0) {
            for (int j = 0; j < N; ++j) {
                a[i][j] = num++;
            }
        } else {
            for (int j = N - 1; j >= 0; --j) {
                a[i][j] = num++;
            }
        }
    }

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            cout << setw(3) << a[i][j];
        }
        cout << '\n';
    }

    return 0;
}
